public String minWindow(String s, String t) {
    if (t.isEmpty()) return "";
    Map<Character,Integer> need = new HashMap<>(), window = new HashMap<>();
    for (char c : t.toCharArray()) need.merge(c,1,Integer::sum);
    int have=0, required=need.size(), l=0, resL=0, resLen=Integer.MAX_VALUE;
    for (int r=0; r<s.length(); r++) {
        char c = s.charAt(r);
        window.merge(c,1,Integer::sum);
        if (need.containsKey(c) && window.get(c).equals(need.get(c))) have++;
        while (have==required) {
            if (r-l+1<resLen) { resLen=r-l+1; resL=l; }
            char lc=s.charAt(l++);
            if (need.containsKey(lc) && window.merge(lc,-1,Integer::sum)<need.get(lc)) have--;
        }
    }
    return resLen==Integer.MAX_VALUE ? "" : s.substring(resL,resL+resLen);
}

