public int ladderLength(String begin, String end, List<String> wordList) {
    Set<String> ws=new HashSet<>(wordList);
    if(!ws.contains(end)) return 0;
    Queue<String> q=new LinkedList<>();
    Set<String> visited=new HashSet<>();
    q.add(begin); visited.add(begin);
    int steps=1;
    while(!q.isEmpty()) {
        for(int sz=q.size();sz>0;sz--) {
            String w=q.poll();
            for(int i=0;i<w.length();i++) for(char c='a';c<='z';c++) {
                String nw=w.substring(0,i)+c+w.substring(i+1);
                if(nw.equals(end)) return steps+1;
                if(ws.contains(nw)&&!visited.contains(nw)) { visited.add(nw); q.add(nw); }
            }
        }
        steps++;
    }
    return 0;
}

