public int[] dijkstra(List<int[]>[] graph, int src) {
    int n=graph.length;
    int[] dist=new int[n];
    Arrays.fill(dist,Integer.MAX_VALUE);
    dist[src]=0;
    PriorityQueue<int[]> pq=new PriorityQueue<>(Comparator.comparingInt(a->a[0]));
    pq.add(new int[]{0,src});
    while(!pq.isEmpty()) {
        int[] cur=pq.poll();
        int d=cur[0], u=cur[1];
        if(d>dist[u]) continue;
        for(int[] e:graph[u]) if(dist[u]+e[1]<dist[e[0]]) {
            dist[e[0]]=dist[u]+e[1]; pq.add(new int[]{dist[e[0]],e[0]});
        }
    }
    return dist;
}

