class Codec:
    def serialize(self, root):
        res = []
        q = deque([root])
        while q:
            node = q.popleft()
            if node: res.append(str(node.val)); q.append(node.left); q.append(node.right)
            else: res.append('N')
        return ','.join(res)
    def deserialize(self, data):
        vals = data.split(',')
        root = TreeNode(int(vals[0])) if vals[0]!='N' else None
        q = deque([root]); i = 1
        while q:
            node = q.popleft()
            if node:
                node.left=TreeNode(int(vals[i])) if vals[i]!='N' else None; i+=1
                node.right=TreeNode(int(vals[i])) if vals[i]!='N' else None; i+=1
                q.append(node.left); q.append(node.right)
        return root

